local function is_allowed_endpoint()
    for _, allowed_endpoint in ipairs(allowed_endpoints) do
        if ngx.var.uri:find(allowed_endpoint, 1, true) then
            return true
        end
    end
    return false
end

local function main()
    local auth_header = find_auth_header()

    if not auth_header then
        ngx.exit(401) -- Unauthorized
        return
